+/// MIN(col) for i64
+pub fn minI64(col: []const i64) ?i64 {
+    if (col.len == 0) return null;
+
+    var acc: Vec8i64 = @splat(std.math.maxInt(i64));
+    var i: usize = 0;
+
+    // SIMD path
+    while (i + 8 <= col.len) : (i += 8) {
+        const batch: Vec8i64 = col[i..][0..8].*;
+        acc = @min(acc, batch);
+    }
+
+    // Horizontal min
+    var result: i64 = @reduce(.Min, acc);
+
+    // Scalar remainder
+    while (i < col.len) : (i += 1) {
+        result = @min(result, col[i]);
+    }
+    return result;
+}
