+        return initFromFile(file);
+    }
+
+    /// Open with absolute path
+    pub fn openAbsolute(path: []const u8) !Self {
+        const file = try std.fs.openFileAbsolute(path, .{});
+        errdefer file.close();
+
+        return initFromFile(file);
+    }
